<script setup lang="ts">import DomainRulesTab from './DomainRulesTab.vue'; import { wafApi } from '@/lib/api/waf'; defineProps<{ domainId:string }>(); const helpItems=[{title:'Start with log',body:'Use Log first for new patterns, watch security events, then switch to Block when false positives look low.'},{title:'Pattern examples',body:'path_prefix /admin, user_agent_contains sqlmap, ip_cidr 203.0.113.0/24, method_is POST.'},{title:'Priority',body:'Lower numbers run first. Put explicit allow rules before broad block rules.'}]; const fields=[{key:'enabled',label:'Enabled',type:'checkbox' as const,default:true,help:'Turn off a rule temporarily without losing its match settings.'},{key:'name',label:'Name',default:'',placeholder:'Block admin scanners',help:'Use a short purpose-driven name that shows up clearly in security events.'},{key:'type',label:'Type',options:['path_contains','path_prefix','user_agent_contains','ip_cidr','country_is','method_is','header_contains'],default:'path_contains',help:'Choose what part of the request should be inspected.'},{key:'pattern',label:'Pattern',default:'',placeholder:'/admin',help:'Format depends on type: path text, CIDR, country code, HTTP method, or header text.'},{key:'action',label:'Action',options:['block','log','allow'],default:'block',help:'Log is safest for testing. Block returns 403 when matched. Allow can exempt trusted traffic.'},{key:'priority',label:'Priority',type:'number' as const,default:100,placeholder:'100',help:'Rules with lower priority values are evaluated first.'},{key:'description',label:'Description',default:'',placeholder:'Blocks suspicious requests to admin paths',help:'Record why the rule exists and when it should be revisited.'}]; const columns=[{key:'enabled',label:'Enabled'},{key:'name',label:'Name'},{key:'type',label:'Type'},{key:'pattern',label:'Pattern'},{key:'action',label:'Action'},{key:'managed_by',label:'Managed'},{key:'actions',label:'Actions'}];</script>
